144	const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
145	  const rawPayout = step.incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
146	  const payout = roundDownInMHPCOsFavor(Math.min(rawPayout, policy.remainingCap));
147	  policy.remainingCap -= payout;
148	  return { payout, remainingCap: policy.remainingCap };
149	};
