158	      const policy: Policy = {
159	        items: step.items,
160	        remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
161	      };
162	      policies.push(policy);
163	      const premium = quotePremium(step, { customer, quoteIndex });
164	      quoteIndex += 1;
165	      return { premium };
166	    }
167	    return processClaim(policies[step.policy], step);
168	  });
169	  return { results };
170	};
